#!/usr/bin/env bash
# Rebuild gemma3-4b-it.knot with fixed language_model.* prefix handling.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI="$SCRIPT_DIR/distributed-inference"
YAML="$SCRIPT_DIR/cloudbuild-gemma3-4b-reencode.yaml"

TMPDIR="$(mktemp -d)"
trap 'rm -rf "$TMPDIR"' EXIT

mkdir -p "$TMPDIR/open-source/gnosis/distributed-inference"

cp "$YAML"                    "$TMPDIR/"
cp "$DI/encode-knot.py"       "$TMPDIR/open-source/gnosis/distributed-inference/"
cp "$DI/upload-to-r2.py"      "$TMPDIR/open-source/gnosis/distributed-inference/"

echo "[submit] tmpdir contents:"
find "$TMPDIR" -type f | sort

echo "[submit] submitting build (model=google/gemma-3-4b-it)"
gcloud builds submit "$TMPDIR" \
  --config="$TMPDIR/cloudbuild-gemma3-4b-reencode.yaml" \
  --project=neutral-418500 \
  --async
